async (params, browser) => {
  // Search sorted by rating
  await browser.open(`https://www.yelp.com/search?find_desc=${params.query}&find_loc=${params.location}&sortby=rating`)

  // Wait for results
  await browser.waitForSelector('[class*=\'businessName\'], [data-testid=\'serp-ia-card\']', 15000)

  await browser.wait(2000)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract comparison data
  const comparison_data = await browser.evaluate(`const items = []; const cards = document.querySelectorAll('[data-testid="serp-ia-card"], [class*="container"][class*="hoverable"], li[class*="border"]'); for (let i = 0; i < Math.min(cards.length, 20); i++) { const el = cards[i]; const nameEl = el.querySelector('[class*="businessName"] a, h3 a, a[href*="/biz/"]'); const ratingEl = el.querySelector('[class*="star"][aria-label], [role="img"][aria-label]'); const reviewCountEl = el.querySelector('[class*="reviewCount"]'); const categoryEl = el.querySelector('[class*="category"] a'); const priceEl = el.querySelector('[class*="priceRange"]'); const addressEl = el.querySelector('address, [class*="address"]'); const linkEl = el.querySelector('a[href*="/biz/"]'); items.push({ name: nameEl ? nameEl.textContent.trim() : '', rating: ratingEl ? (ratingEl.getAttribute('aria-label') || '') : '', review_count: reviewCountEl ? reviewCountEl.textContent.trim() : '', category: categoryEl ? categoryEl.textContent.trim() : '', price_range: priceEl ? priceEl.textContent.trim() : '', address: addressEl ? addressEl.textContent.trim() : '', url: linkEl ? linkEl.href : '' }); } return { query: params.query, location: '' + params.location + '', business_count: items.length, businesses: items }`)

  return comparison_data
}
